import asyncio
import uuid
from collections import defaultdict

class Player:
    def __init__(self, name):
        self.name = name
        self.inventory = {}

class Item:
    def __init__(self, id, name, quantity):
        self.id = id
        self.name = name
        self.quantity = quantity

class GameServer:
    def __init__(self):
        self.players = {}
        self.items = defaultdict(int)

    async def handle_connection(self, websocket, player_name):
        self.players[player_name] = Player(player_name)
        await websocket.wait_closed()

    async def handle_message(self, websocket, message):
        if message['type'] == 'add_item':
            item_id = message['item_id']
            quantity = message['quantity']
            if item_id not in self.items:
                self.items[item_id] += quantity
                await websocket.send({'message': f'Item {item_id} added to the game.'})
            else:
                await websocket.send({'message': 'Item already exists in the game.'})

        elif message['type'] == 'remove_item':
            item_id = message['item_id']
            quantity = message['quantity']
            if self.items[item_id] >= quantity:
                self.items[item_id] -= quantity
                await websocket.send({'message': f'Item {item_id} removed from the game.'})
            else:
                await websocket.send({'message': 'Not enough items in the game to remove.'})

        elif message['type'] == 'trade_item':
            sender_name = message['sender']
            receiver_name = message['receiver']
            item_id = message['item_id']
            quantity = message['quantity']

            if sender_name not in self.players or receiver_name not in self.players:
                await websocket.send({'message': 'Invalid player name.'})
                return

            sender_player = self.players[sender_name]
            receiver_player = self.players[receiver_name]

            if item_id not in sender_player.inventory or sender_player.inventory[item_id] < quantity:
                await websocket.send({'message': 'Sender does not have enough items to trade.'})
                return

            # Update item ownership
            sender_player.inventory[item_id] -= quantity
            receiver_player.inventory[item_id] = receiver_player.inventory.get(item_id, 0) + quantity

            await websocket.send({'message': f'Item {item_id} traded successfully.'})

    async def handle_websocket(self, websocket):
        player_name = websocket.path.split('/')[-1]
        await self.handle_connection(websocket, player_name)

        try:
            async for message in websocket:
                if not isinstance(message, dict) or 'type' not in message:
                    continue

                await self.handle_message(websocket, message)
        except Exception as e:
            print(f'Error handling WebSocket: {e}')

    async def run(self):
        server = await websockets.serve(self.handle_websocket, 'localhost', 8765)

        try:
            await asyncio.Future()  # Run forever
        finally:
            server.close()

if __name__ == '__main__':
    game_server = GameServer()
    asyncio.run(game_server.run())